const ex = $json.execution || {};
const wf = $json.workflow || {};
const err = ex.error || {};
const name = wf.name || '';
// Derive workflow_label from name pattern 'SV Workflow X — ...'
let label = 'unknown';
const m = name.match(/SV Workflow ([A-Z][a-zA-Z\-]*)/i);
if (m) label = m[1];
else if (/Pre-A/i.test(name)) label = 'Pre-A';
const execUrl = `https://svsolutionarchitects.app.n8n.cloud/workflow/${wf.id || ''}/executions/${ex.id || ''}`;
return [{ json: {
  execution_id: ex.id || 'unknown',
  workflow_n8n_id: wf.id || null,
  workflow_n8n_name: name,
  workflow_label: label,
  failed_node: ex.lastNodeExecuted || null,
  error_message: err.message || 'no message',
  error_stack: err.stack || null,
  execution_url: execUrl,
  timestamp_utc: new Date().toISOString(),
} }];

const errCtx = $('Extract Error Context').item.json;
const upstream = $input.first().json;
let ctx = null;
if (Array.isArray(upstream)) ctx = upstream[0] || null;
else if (upstream && (upstream.execution_id || upstream.candidate_id)) ctx = upstream;
return [{ json: {
  ...errCtx,
  candidate_id: ctx?.candidate_id || null,
  candidate_email: ctx?.candidate_email || null,
  session_id: ctx?.session_id || null,
  trigger_event: ctx?.trigger_event || null,
  trigger_payload: ctx?.trigger_payload || null,
} }];

const c = $('Merge Context').item.json;
const subject = `[SV Pipeline ALERT] Workflow ${c.workflow_label} failed — ${c.failed_node || 'unknown node'}`;
const lines = [
  `A production workflow failed. A candidate may need manual processing.`,
  ``,
  `Workflow: ${c.workflow_n8n_name} (${c.workflow_label})`,
  `Execution: ${c.execution_id}`,
  `Failed at: ${c.failed_node || '(unknown)'}`,
  `Error: ${c.error_message}`,
  ``,
];
if (c.candidate_id) {
  lines.push(`Candidate: ${c.candidate_id} (${c.candidate_email || 'no email'})`);
  if (c.session_id) lines.push(`Session: ${c.session_id}`);
  lines.push('');
}
lines.push(`n8n execution: ${c.execution_url}`);
lines.push('');
lines.push('Next steps:');
lines.push(' 1. Open the execution URL above to diagnose the failed node.');
lines.push(' 2. If the candidate is stuck (no comment, no stage move, no email sent),');
lines.push('    manually process them via Workable UI or re-fire the workflow.');
lines.push(' 3. Mark resolved in workflow_errors when complete:');
lines.push(`    UPDATE workflow_errors SET resolved_at=NOW(), resolution_note='...' WHERE execution_id='${c.execution_id}';`);
if (c.candidate_id) {
  lines.push('');
  lines.push('A notification comment has also been posted on the candidate in Workable.');
}
const body = lines.join('\n');
return [{ json: { ...c, email_subject: subject, email_body: body, email_subject_json_str: JSON.stringify(subject), email_body_json_str: JSON.stringify(body) } }];

const c = $('Merge Context').item.json;
const body = [
  '⚠️ Automated screening encountered a technical error and could not complete this evaluation. The talent acquisition team has been notified and will manually review this candidate.',
  '',
  `Error reference: WF-${c.workflow_label} / Exec ${c.execution_id} / ${c.timestamp_utc}`,
].join('\n');
return [{ json: { ...c, comment_body: body, comment_body_json_str: JSON.stringify(body) } }];
